      function printContract() {
        // 设置页面缩放为85%
        document.body.style.zoom = "85%";
        // 延迟执行打印，确保缩放和页码计算生效
        setTimeout(function() {
          calculatePages();
          window.print();
          // 打印完成后恢复默认缩放
          document.body.style.zoom = "100%";
        }, 100);
      }
      
      // 计算总页数
      function calculatePages() {
        const body = document.body;
        const pageHeight = 297 * 96 / 25.4; // A4高度（mm转换为像素，96dpi）
        const bodyHeight = body.offsetHeight;
        const totalPages = Math.ceil(bodyHeight / pageHeight);
        
        // 更新所有页脚的总页数
        const totalPagesElements = document.querySelectorAll('#totalPages');
        totalPagesElements.forEach(el => {
          el.textContent = totalPages.toString();
        });
        
        // 如果只有一页，隐藏页脚
        if (totalPages <= 1) {
          const footers = document.querySelectorAll('.footer');
          footers.forEach(f => {
            f.style.display = 'none';
          });
        }
      }
      
      // 页面加载完成后执行
      window.onload = function() {
        calculatePages();
        
        // 在打印前更新页码
        window.addEventListener('beforeprint', function() {
          calculatePages();
        });
      };
